mapper.select:
SELECT title 
FROM Community_Post 
WHERE post_no = #{targetId}

mapper.insert:
INSERT INTO Community_Post (
    user_id, category, title, content, reg_date
) VALUES (
    #{userId}, #{category}, #{title}, #{content}, CURRENT_TIMESTAMP
)

mapper.select:
SELECT p.post_no AS postNo, p.user_id AS userId, CASE WHEN m.status = 'WITHDRAWN' THEN '탈퇴회원' ELSE IFNULL(d.nickname, p.user_id) END AS nickname, p.category, p.title, p.content, DATE_FORMAT(p.reg_date, '%Y-%m-%d') AS regDate, p.view_cnt AS viewCnt, p.like_cnt AS likeCnt, p.is_deleted AS isDeleted, (SELECT COUNT(*) FROM comment c WHERE c.post_no = p.post_no) AS commentCnt FROM Community_Post p LEFT JOIN MEMBER m ON p.user_id = m.user_id LEFT JOIN USER_DETAIL d ON p.user_id = d.user_id WHERE p.is_deleted = 0
AND p.category = #{category}
AND p.title LIKE CONCAT('%', #{searchKeyword}, '%')
AND p.user_id LIKE CONCAT('%', #{searchKeyword}, '%')
AND (p.title LIKE CONCAT('%', #{searchKeyword}, '%') OR p.user_id LIKE CONCAT('%', #{searchKeyword}, '%'))
ORDER BY p.reg_date DESC LIMIT #{startIndex}, #{pageSize}

mapper.update:
UPDATE Community_Post 
SET view_cnt = view_cnt + 1
WHERE post_no = #{postNo}
